-- drop existing tables if they exist
drop table if exists cards cascade;
drop table if exists transactions cascade;
drop table if exists accounts cascade;
drop table if exists loans cascade;
drop table if exists clients cascade;

create table clients (  -- creation of table "clients"
    client_id serial primary key,
    full_name varchar(100) not null,
    email varchar(100),
    phone varchar(20),
    city varchar(50),
    country varchar(50),
    date_of_birth date
);

create table accounts (  -- creation of table "accounts"
    account_id serial primary key,
    client_id int not null,
    account_type varchar(20),
    currency varchar(5),
    balance numeric(15, 2),
    opened_date date,
    iban varchar(34),
    foreign key (client_id) references clients(client_id)
);

create table transactions (  -- creation of table "transactions"
    transaction_id serial primary key,
    account_id int not null,
    transaction_type varchar(20),
    amount numeric(15, 2),
    currency varchar(5),
    transaction_date date,
    status varchar(15),
    description varchar(100),
    foreign key (account_id) references accounts(account_id)
);

create table loans (  -- creation of table "loans"
    loan_id serial primary key,
    client_id int not null,
    loan_type varchar(30),
    amount numeric(15, 2),
    interest_rate numeric(5, 2),
    start_date date,
    end_date date,
    status varchar(15),
    foreign key (client_id) references clients(client_id)
);

create table cards (  -- creation of table "cards"
    card_id serial primary key,
    account_id int not null,
    card_type varchar(20),
    card_number varchar(20),
    expiry_date varchar(7),
    status varchar(10),
    issued_date date,
    foreign key (account_id) references accounts(account_id)
);

