-- запит: клієнти з активним кредитом, завершиними транзакціями, які були зроблені після 01.01.2022
select -- обираємо колонки: базову інфо про клієнта, баланс, карту, тип кредиту та відсоткову ставту
a.account_id, 
cl.full_name, 
cl.email, 
cl.phone, 
ca.card_type, 
ca.card_number, 
a.balance, 
l.loan_type, 
l.interest_rate, 
count(t.transaction_id) as number_of_transactions, -- к-сть транзакцій клієнта 
sum(t.amount) as transaction_amount, -- загальна сума всіх транзакцій 
avg(t.amount) as avg_transaction_amount -- середня сума однієї транзації 
from clients cl -- з таблиці clients
join accounts a on cl.client_id = a.client_id -- з'єднуємо clients з accounts
join transactions t on a.account_id = t.account_id -- з'єднуємо accounts з transactions
join loans l on cl.client_id = l.client_id -- з'єднуємо clients з loans
join cards ca on a.account_id = ca.account_id -- з'єднуємо accounts з cards
where t.transaction_date > '2022-01-01' and t.status = 'Completed' and l.status = 'Active' -- фільтруємо: хочемо бачити траназкції тільки після 01.01.2022 та транзакції ті, що завершені та щоб кредит був активний
group by a.account_id, cl.full_name, cl.email, cl.phone, ca.card_type, ca.card_number, a.balance, l.loan_type, l.interest_rate -- групуємо по тим колонках які ми обрали в select та які не мають агрегатних функцій
order by sum(t.amount) desc; -- сортуємо по сумі транзакцій в спадаючому порядку

with active_clients as( -- cte: тимчасова таблиця active_clients (той самий запит, що і вище але через cte)
select -- обираємо колонки: базову інфо про клієнта, баланс, карту, тип кредиту та відсоткову ставту
a.account_id, 
cl.full_name, 
cl.email, 
cl.phone, 
ca.card_type, 
ca.card_number, 
a.balance, 
l.loan_type, 
l.interest_rate, 
count(t.transaction_id) as number_of_transactions, -- к-сть транзакцій клієнта 
sum(t.amount) as transaction_amount, -- загальна сума всіх транзакцій
avg(t.amount) as avg_transaction_amount -- середня сума однієї транзації 
from clients cl -- з таблиці clients
join accounts a on cl.client_id = a.client_id -- з'єднуємо clients з accounts
join transactions t on a.account_id = t.account_id -- з'єднуємо accounts з transactions
join loans l on cl.client_id = l.client_id -- з'єднуємо clients з loans
join cards ca on a.account_id = ca.account_id -- з'єднуємо accounts з cards
where t.transaction_date > '2022-01-01' and t.status = 'Completed' and l.status = 'Active' -- фільтруємо: хочемо бачити траназкції тільки після 01.01.2022 та транзакції ті, що завершені та щоб кредит був активний
group by a.account_id, cl.full_name, cl.email, cl.phone, ca.card_type, ca.card_number, a.balance, l.loan_type, l.interest_rate -- групуємо по тим колонках які ми обрали в select та які не мають агрегатних функцій
)
select * -- вибираємо все 
from active_clients -- з тимчасової таблиці active_clients
order by transaction_amount desc; -- сортуємо по сумі транзакцій в спадаючому порядку


-- union all: об'єднаємо клієнтів з великими транзакціями (>75000) та окремо ті клієнти, що з Києва 
-- зберігаємо дублікати, київські клієнти мають з'явитися в результаті окремими рядками, незалежно від того чи є вони вже в першому підзапиті

-- перший підзапит: клієнти, які мають завершені транзакції та їх сума більше ніж 75000
select -- обираємо колонки: базову інфо про клієнта (id, ім'я/прізвище, емейл, телефон, місто)
cl.client_id, 
cl.full_name, 
cl.email, 
cl.phone, 
cl.city,
sum(t.amount) as transaction_amount -- загальна сума всіх транзакцій та надаємо назву
from clients cl -- з таблиці clients
join accounts a on cl.client_id = a.client_id -- з'єднуємо clients з accounts
join transactions t on a.account_id = t.account_id -- з'єднуємо accounts з transactions
where t.status = 'Completed' -- фільтруємо: щоб статус тразакції був завершений
group by cl.client_id, cl.full_name, cl.email, cl.phone, cl.city -- групуємо по тим колонках які ми обрали в select та які не мають агрегатних функцій
having sum(t.amount) > 75000 -- фільтруємо після групування: вибираємо транзації з сумою більше ніж 75000

union all -- об'єднуємо з другим підзапитом, зберігаємо всі рядки без видалення дублікатів
-- другий підзапит: всі клієнти, які з Києва
-- суму транзакцій не рахуємо, бо хочемо знайти саме по місту
select -- обираємо колонки: базову інфо про клієнта (id, ім'я/прізвище, емейл, телефон, місто)
client_id, 
full_name, 
email, 
phone, 
city, 
0 as transaction_amount -- суму транзакцій тут не аналізуємо, бо клієнти додаються за містом
from clients -- з таблиці clients
where city = 'Kyiv' -- фільтруємо по місту Київ
group by client_id, full_name, email, phone, city; -- групуємо по тим колонках які ми обрали в select та які не мають агрегатних функцій

